noncompliant:
resource appService 'Microsoft.Web/sites@2022-09-01' = {
  name: 'example'
  properties: {
    authentication: {
      enabled: false // Sensitive: anonymous access allowed
    }
  }
}

resource appService 'Microsoft.Web/sites@2022-09-01' = {
  name: 'example'
  // Sensitive: no authentication defined
}

compliant:
resource appService 'Microsoft.Web/sites@2022-09-01' = {
  name: 'example'
  properties: {
    authentication: {
      enabled: true
      activeDirectory: {
        clientId: 'xxxx'
      }
    }
  }
}
